ruleSearch.bookList:
.sear li
<js>
result.toArray().slice(0,3).map(o=>{
    var url = baseUrl.match(/(.+\/\/.+?\/)/)[1] + o.select('a:eq(1)').attr('href');
    var J = org.jsoup.Jsoup.parse(java.ajax(url));
    var o = selector =>String(J.select(selector).text());
    return {
        name: o('h1').replace(/\s.*/,''),
        author: o('.ml1 ul li:eq(2)').replace(/.*：/,''),
        kind: o('.ml1 ul li:eq(0)').replace(/.*：/,'').replace(/\s-\s/,',') + ',' + o('.ml1 ul li:eq(3)').replace(/.*：/,''),
        wordCount: o('.ml1 ul li:eq(1)').replace(/.*：/,''),
        latest: o('.ml1 ul li:eq(4)'),
        intro: o('.center p'),
        cover: J.select('.ml1 img').attr('src'),
        url: url,
    }
});
</js>

ruleToc.chapterList:
@js:list = [];
if (baseUrl.match(/id/)) {
    p = result.match(/=(\d+)">最后1页/)[1];
    for (i = 0; i <= p; i++) {
        list.push({
            text: '第' + [i + 1] + '页',
            href: baseUrl.replace(/,.*$/, '&yeshu=' + i + ',{charset:"gbk"}')
        })
    }
} else list.push({
    text: '空',
    href: ''
});
list
